+    let mut trk = test_tracker();
+    trk.record_error(ProtocolErrorKind::Recoverable, "disconnected");
+    trk.record_error(ProtocolErrorKind::Transient, "timeout");
+
+    let snap = trk.telemetry().snapshot();
